	Only allow via CLI
***********************************************************************************************************/
if (php_sapi_name() !== 'cli') { die("This script can only be executed from the command line."); exit(); }

// Get the directory of the current script
$script_dir = realpath(dirname(__FILE__));

// Go three levels up
$target_dir = realpath($script_dir . '/../../..');

// Define target paths
$test_dir = $target_dir . '/_testing/sm_run';
$debug_file = $test_dir . '/php.debug';

// Create directory recursively if it doesn't exist
if (!is_dir($test_dir)) {
    mkdir($test_dir, 0777, true);
}

// Create the file if it doesn't exist
if (!file_exists($debug_file)) {
    touch($debug_file);
}

// Change permissions recursively
function chmodRecursive($path, $perm) {
    if (is_dir($path)) {
        chmod($path, $perm);
        $items = scandir($path);
        foreach ($items as $item) {
            if ($item != '.' && $item != '..') {
                chmodRecursive($path . '/' . $item, $perm);
            }
        }
    } else {
        chmod($path, $perm);
    }
}

// Apply 0777 permissions to _testing directory
chmodRecursive($target_dir . '/_testing', 0777);

echo "Setup complete.\n";